SELECT e.id, e.employee_no AS employeeNo, e.name, d.dept_name AS deptName, p.position_name AS positionName, e.grade, e.status, e.entry_date AS entryDate FROM employee e LEFT JOIN department d ON e.dept_id = d.id LEFT JOIN position p ON e.position_id = p.id
AND e.dept_id = #{deptId}
AND e.status = #{status}
AND (e.name LIKE CONCAT('%', #{keyword}, '%') OR e.employee_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY e.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM employee e


        AND e.dept_id = #{deptId}


        AND e.status = #{status}


        AND (e.name LIKE CONCAT('%', #{keyword}, '%')
             OR e.employee_no LIKE CONCAT('%', #{keyword}, '%'))

